import { jsx, jsxs } from 'react/jsx-runtime';
import { memo, useCallback, useMemo } from 'react';
import { Position } from '@xyflow/react';
import { useNodesEdges } from './hooks/node.js';
import { NodeLinkedField } from './components/NodeLinkedField.js';
import { useGraphConfig } from './context/GraphConfigContext.js';
import { NodeOutputField } from './components/NodeOutputField.js';
import { NodeContainer } from './components/NodeContainer.js';
import { useFocusBlur } from './hooks/focus.js';
import { Handle } from './components/Handle.js';
import { InputGroup } from './components/InputGroup.js';
import './components/Label.js';
import './config.js';
import './components/inputs.js';
import './components/NodeInputField.js';
import './components/NodeBaseInputField.js';
import './style-inject.es-77_9GKgS.js';
import './components/NodeCheckboxField.js';
import './components/NodeSelectField.js';
import './components/NodeToggleField.js';
import './components/NodeHeader.js';
import './index-FcVUitMS.js';

/**
 * Determines whether a node component should be re-rendered based
 * on whether the node's selection or data has changed.
 * @param a {Node}
 * @param b {Node}
 */
const isComponentChanged = (a, b) => a.selected === b.selected && JSON.stringify(a.data) === JSON.stringify(b.data); // switched from lodash because bundle size was so large
function buildNode(nodeConfig) {
    function component(node) {
        const [config] = useGraphConfig();
        const [isFocused, onFocus, onBlur] = useFocusBlur();
        function getInputElements(inputs, edges) {
            const targetEdges = edges.filter((edge) => edge.target === node.id);
            return inputs.map((input) => getInputElement(config, targetEdges, input, onFocus, onBlur));
        }
        const getHandlesForInputs = useCallback((configs) => {
            return configs.map((inputConfig) => (jsx(Handle, { handleType: "target", position: Position.Left, ...config.getInputConfig(inputConfig) }, inputConfig.id)));
        }, [config]);
        // Construct memoized input components based on the node config
        const edges = useNodesEdges(node.id);
        const edgeIds = edges.map((e) => e.id).join();
        const inputConfigs = nodeConfig.inputs ?? [];
        // Construct memoized input and output components based on the node config
        const inputs = useMemo(() => {
            return getInputElements(inputConfigs.filter((input) => !input.group), edges);
        }, [inputConfigs, config, node, edgeIds]);
        const outputs = useMemo(() => {
            return (nodeConfig.outputs ?? []).map((output) => getOutputElements(config, output));
        }, [config, node]);
        // Input groups are those inputs that should be rendered under a collapsable accordion
        const inputGroups = useMemo(() => {
            const grouped = inputConfigs
                .filter((input) => input.group)
                .reduce((acc, input) => {
                const group = input.group;
                if (!acc[group])
                    acc[group] = [];
                acc[group].push(input);
                return acc;
            }, {});
            return Object.entries(grouped).map(([group, inputs]) => (jsx(InputGroup, { label: group, handles: getHandlesForInputs(inputs), children: getInputElements(inputs, edges) }, group)));
        }, [edgeIds]);
        return (jsx(NodeContainer, { draggable: !isFocused, node: node, children: jsxs("div", { style: {
                    padding: '8px 0 12px',
                    display: 'flex',
                    flexDirection: 'column',
                }, children: [outputs, inputs, inputGroups] }) }));
    }
    return memo(component, isComponentChanged);
}
function getInputElement(graphConfig, edges, input, onFocus, onBlur) {
    const inputConfig = graphConfig.getInputConfig(input);
    if (edges.find((edge) => edge.targetHandle === input.id)) {
        return jsx(NodeLinkedField, { ...inputConfig }, inputConfig.id);
    }
    const Element = graphConfig.getInputComponent(input.valueType);
    if (Element) {
        return (jsx(Element, { onFocus: onFocus, onBlur: onBlur, slots: {
                Handle: !inputConfig.isConstant
                    ? () => (jsx(Handle, { handleType: "target", position: Position.Left, ...inputConfig }))
                    : undefined,
            }, ...inputConfig }, input.id));
    }
    else {
        return jsx(NodeLinkedField, { ...inputConfig }, input.id);
    }
}
function getOutputElements(graphConfig, output) {
    const outputConfig = graphConfig.getOutputConfig(output);
    return jsx(NodeOutputField, { ...outputConfig }, output.id);
}

export { buildNode };
