import "./styles.css";
import {
  NodeGraphEditor,
  GraphConfigProvider,
  useBuildGraphConfig,
} from "@clarkmcc/ngraph";
import {
  Background,
  BackgroundVariant,
  ReactFlowProvider,
} from "@xyflow/react";

export default function App() {
  // We use useBuildGraphConfig to construct a config object for our node
  // graph. This hook is especially powerful for more complicated projects
  // like custom nodes and custom node imputs. For now, we just construct
  // our config object with it.
  const config = useBuildGraphConfig({
    // Value types are the types supported by node handles and node edges.
    // You can add primitive value types like 'string', and 'number', along
    // with any color customizations you want.
    valueTypes: {
      string: {
        name: "String",
        color: "#a1a1a1",
        inputType: "value",
        defaultValue: "",
      },
      // You can also add your own value types like 'person' and just not specify
      // an input type. This means that you won't have an input element rendered
      // to set the value, but you will have a handle where you can connect any
      // 'person' edge.
      person: {
        name: "Person",
        color: "#dc2626",
        inputType: null,
      },
    },
    // Node groups define a group name and color for your nodes. Every node in the
    // group will render its header with this color.
    nodeGroups: {
      default: {
        name: "Default",
        color: "#dc2626",
      },
    },
    // Nodes are the actual node types that are supported by the graph
    nodes: {
      person: {
        // Our first node type will be a 'person' and be part of the 'default'
        // group. This node is going to allow us to construct a person from a
        // first and last name.
        //
        // We define two string inputs for the name. These inputs will be rendered
        // using text fields because their value types are 'string', and the input
        // type of 'string' is 'value'
        name: "Person",
        group: "default",
        inputs: [
          {
            name: "First Name",
            id: "firstName",
            valueType: "string",
          },
          {
            name: "Last Name",
            id: "lastName",
            valueType: "string",
          },
        ],
        // The output is a valueType 'person'. This doesn't really mean anything other
        // than only handles that are also 'person' will be able to be connected and the
        // output handle, and edge will be styled based what you specified in the 'person'
        // value type
        outputs: [
          {
            name: "Person",
            id: "person",
            valueType: "person",
          },
        ],
      },
      greeter: {
        name: "Greeter",
        group: "default",
        inputs: [
          {
            name: "Person",
            id: "person",
            valueType: "person",
          },
        ],
      },
    },
  });

  return (
    <div className="container">
      <ReactFlowProvider>
        <GraphConfigProvider defaultConfig={config}>
          <NodeGraphEditor
            // The following nodes and edges are defined exactly like you would in reactflow
            // https://reactflow.dev/learn/customization/custom-nodes
            defaultNodes={[
              {
                id: "1",
                type: "person",
                position: { x: 50, y: 50 },
                data: {},
              },
              {
                id: "2",
                type: "greeter",
                position: { x: 400, y: 100 },
                data: {},
              },
            ]}
            defaultEdges={[
              {
                id: "e1",
                source: "1",
                target: "2",
                sourceHandle: "person",
                targetHandle: "person",
              },
            ]}
          >
            <Background color="#52525b" variant={BackgroundVariant.Dots} />
          </NodeGraphEditor>
        </GraphConfigProvider>
      </ReactFlowProvider>
    </div>
  );
}
