import { jsxs, jsx } from 'react/jsx-runtime';
import { memo, useCallback } from 'react';
import { useNodeFieldValue } from '../hooks/node.js';
import '@xyflow/react';

const NodeCheckboxField = memo(({ isConstant, slots, ...props }) => {
    const Handle = slots?.Handle;
    const [value, setValue] = useNodeFieldValue(props.id, props.defaultValue);
    const handleChange = useCallback((e) => setValue(e.target.checked), [setValue]);
    return (jsxs("div", { style: {
            margin: '4px 0',
            padding: '0 12px',
            position: 'relative',
            display: 'flex',
            alignItems: 'center',
        }, children: [isConstant || !Handle ? null : jsx(Handle, {}), jsx("input", { style: {
                    appearance: value ? undefined : 'none',
                    background: '#545555',
                    border: 'none',
                    borderRadius: 3,
                    width: 14,
                    height: 14,
                    margin: '0 4px 0 0',
                }, type: "checkbox", onChange: handleChange, checked: value }), jsx("label", { style: {
                    color: '#fff',
                    fontSize: '12px',
                    textShadow: '0 1px rgba(0,0,0,0.4)',
                }, children: props.name })] }));
});

export { NodeCheckboxField };
