import { useGraphConfig } from '../context/GraphConfigContext.js';
import { useReactFlow, useNodes, addEdge } from '@xyflow/react';
import { useCallback } from 'react';
import 'react/jsx-runtime';
import '../config.js';
import '../components/inputs.js';
import '../components/NodeInputField.js';
import '../components/NodeBaseInputField.js';
import './node.js';
import '../style-inject.es-77_9GKgS.js';
import '../components/NodeCheckboxField.js';
import '../components/NodeSelectField.js';
import '../components/NodeToggleField.js';

function useSocketConnect() {
    const [config] = useGraphConfig();
    const { setEdges, getEdges } = useReactFlow();
    const nodes = useNodes();
    return useCallback((params) => {
        if (nodes.length === 0 ||
            params.target === null ||
            params.source === null) {
            return;
        }
        const targetNode = nodes.find((node) => node.id === params.target);
        const targetNodeType = config.getNodeConfig(targetNode.type);
        const targetInput = targetNodeType.inputs.find((input) => input.id === params.targetHandle);
        // We remove all edges that have the same target and targetHandle
        // if the target handle is not an array type
        const edgesToRemove = targetInput && !targetInput.isArray
            ? getEdges().filter((e) => e.target === params.target &&
                e.targetHandle === params.targetHandle)
            : [];
        setEdges((edges) => addEdge({
            target: params.target,
            targetHandle: params.targetHandle,
            source: params.source,
            sourceHandle: params.sourceHandle,
            type: 'default',
        }, edges).filter((e) => !edgesToRemove.some((r) => r.id === e.id)));
    }, [nodes, getEdges, setEdges]);
}

export { useSocketConnect };
