import { jsxs, jsx } from 'react/jsx-runtime';
import { memo } from 'react';
import { useNodeFieldValue } from '../hooks/node.js';
import '@xyflow/react';

const NodeToggleField = memo(({ options, isConstant, slots, ...props }) => {
    const Handle = slots?.Handle;
    const [value, setValue] = useNodeFieldValue(props.id, props.defaultValue);
    return (jsxs("div", { style: { position: 'relative' }, children: [isConstant || !Handle ? null : jsx(Handle, {}), jsx("div", { style: {
                    margin: '2px 0',
                    padding: '0 12px',
                    display: 'flex',
                }, children: options.map((n, idx) => (jsx(ToggleButton, { active: n.value === value, onClick: () => setValue(n.value), style: {
                        0: {
                            borderTopRightRadius: 0,
                            borderBottomRightRadius: 0,
                            margin: '0 1px 0 0',
                        },
                        [options.length - 1]: {
                            borderTopLeftRadius: 0,
                            borderBottomLeftRadius: 0,
                        },
                    }[idx], children: n.name }, n.value))) })] }));
});
function ToggleButton({ style, active, onClick, children }) {
    return (jsx("button", { style: {
            background: active ? '#3873b8' : '#545555',
            border: 'none',
            borderRadius: 4,
            padding: '3px 8px',
            color: '#fff',
            textShadow: '0 1px rgba(0,0,0,0.4)',
            fontSize: '12px',
            flex: 1,
            width: '100%',
            ...style,
        }, onClick: onClick, children: children }));
}

export { NodeToggleField };
