import { jsxs, jsx } from 'react/jsx-runtime';
import { memo, useState, useRef } from 'react';

const NodeBaseInputField = memo(({ name, valueType, value, style, inputStyle, onChange, onPointerDown, onPointerLeave, children, }) => {
    const [_value, setValue] = useState(value);
    const [labelVisible, setLabelVisible] = useState(true);
    const ref = useRef(null);
    function handleChange(e) {
        setValue(e.target.value.trim());
    }
    function handleBlur() {
        setLabelVisible(true);
        if (onChange)
            onChange(_value);
    }
    return (jsxs("div", { style: {
            margin: '2px 0',
            padding: '0 12px',
            position: 'relative',
            display: 'flex',
            ...style,
        }, children: [children, jsx("input", { ref: ref, type: valueType, style: {
                    background: '#545555',
                    border: 'none',
                    borderRadius: 3,
                    padding: '3px 8px',
                    color: '#fff',
                    textShadow: '0 1px rgba(0,0,0,0.4)',
                    fontSize: '12px',
                    textAlign: labelVisible ? 'right' : 'left',
                    flex: 1,
                    width: '100%',
                    ...inputStyle,
                }, onChange: handleChange, onFocus: () => setLabelVisible(false), onBlur: handleBlur, onKeyDown: (e) => {
                    if (e.key === 'Enter') {
                        ref.current.blur();
                    }
                }, onPointerDown: onPointerDown, onPointerLeave: onPointerLeave, value: _value }), labelVisible ? (jsx("div", { style: {
                    position: 'absolute',
                    color: '#fff',
                    fontSize: '12px',
                    zIndex: 1,
                    top: 3,
                    left: 20,
                    textShadow: '0 1px rgba(0,0,0,0.4)',
                    backgroundColor: '#545555',
                    paddingRight: 8,
                }, onClick: () => {
                    ref.current.focus();
                }, children: name })) : null] }));
});

export { NodeBaseInputField };
