import { jsxs, jsx } from 'react/jsx-runtime';
import { memo, useRef } from 'react';
import { useNodeFieldValue } from '../hooks/node.js';
import '@xyflow/react';

const NodeSelectField = memo(({ options, isConstant, slots, ...props }) => {
    const Handle = slots?.Handle;
    const [value, setValue] = useNodeFieldValue(props.id, props.defaultValue);
    const ref = useRef(null);
    return (jsxs("div", { style: {
            margin: '2px 0',
            padding: '0 12px',
            position: 'relative',
            display: 'flex',
        }, children: [isConstant || !Handle ? null : jsx(Handle, {}), jsx("select", { style: {
                    background: '#282828',
                    border: '1px solid #3d3d3d',
                    borderRadius: 3,
                    padding: '4px 8px',
                    color: '#fff',
                    textShadow: '0 1px rgba(0,0,0,0.4)',
                    fontSize: '12px',
                    flex: 1,
                    width: '100%',
                    textAlign: 'right',
                    minWidth: '150px',
                }, value: value, onChange: (e) => setValue(e.target.value), children: options.map((opt) => (jsx("option", { value: opt.value, children: opt.name }, opt.value))) }), jsx("div", { style: {
                    position: 'absolute',
                    color: '#fff',
                    fontSize: '12px',
                    zIndex: 1,
                    top: 6,
                    left: 24,
                    textShadow: '0 1px rgba(0,0,0,0.4)',
                    opacity: 0.5,
                }, onClick: () => {
                    ref.current.focus();
                }, children: props.name })] }));
});

export { NodeSelectField };
